import numpy as np

class LassoRegression:
    def __init__(self, alpha: float = 1.0):
        self.alpha = alpha
        self.w = None
        self.b = 0.0

    @staticmethod
    def _soft_threshold(rho, threshold):
        if rho > threshold:
            return rho - threshold
        elif rho < -threshold:
            return rho + threshold
        return 0.0

    def fit(self, X: np.ndarray, y: np.ndarray, epochs: int = 1000, tol: float = 1e-4) -> None:
        N, D = X.shape
        self.w = np.zeros(D)
        self.b = 0.0
        # Precompute column norms squared
        col_norms_sq = np.sum(X ** 2, axis=0)  # (D,)

        for _ in range(epochs):
            w_old = self.w.copy()
            # Update bias (no regularization)
            self.b = np.mean(y - X @ self.w)
            # Coordinate descent over each weight
            for j in range(D):
                # Partial residual (exclude j-th feature)
                r_j = y - self.b - X @ self.w + X[:, j] * self.w[j]
                rho_j = X[:, j] @ r_j
                if col_norms_sq[j] < 1e-10:
                    self.w[j] = 0.0
                else:
                    self.w[j] = self._soft_threshold(rho_j, self.alpha * N) / col_norms_sq[j]
            # Check convergence
            if np.max(np.abs(self.w - w_old)) < tol:
                break

    def predict(self, X: np.ndarray) -> np.ndarray:
        return X @ self.w + self.b
